import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import {
  renderEnum,
  renderModelInterface,
  renderWhereInput,
  renderWhereUniqueInput,
  renderCreateInput,
  renderUpdateInput,
  renderRestClientClass,
} from './template'

/**
 * Resolves the output directory from generator options, supporting both
 * literal paths and env-var references.
 */
function resolveOutput(options: GeneratorOptions): string {
  const output = options.generator.output
  if (output === null) {
    throw new Error(
      '@prisma/generator-rest-client: an `output` path is required in your Prisma schema.\n' +
        'Add `output = "./generated/rest-client"` to the generator block.',
    )
  }
  if (output.fromEnvVar !== null) {
    const value = process.env[output.fromEnvVar]
    if (value === undefined) {
      throw new Error(
        `@prisma/generator-rest-client: environment variable \`${output.fromEnvVar}\` referenced in the generator output is not set`,
      )
    }
    return value
  }
  if (output.value !== null) {
    return output.value
  }
  throw new Error('@prisma/generator-rest-client: could not resolve the output path')
}

const SECTION_SEPARATOR = '\n// =============================================================================\n'

/** Assembles the complete `rest-client.ts` file content from the DMMF document. */
function generateContent(dmmf: GeneratorOptions['dmmf']): string {
  const { models, enums } = dmmf.datamodel

  const parts: string[] = [
    '// Generated by @prisma/generator-rest-client — do not edit directly.',
    '// Regenerate by running `prisma generate`.',
    '// Requires a runtime with global `fetch` and `URL` (Node.js 18+, browsers, Deno, Bun).',
  ]

  if (enums.length > 0) {
    parts.push(
      SECTION_SEPARATOR + '// Enums\n// =============================================================================\n',
      enums.map(renderEnum).join('\n\n'),
    )
  }

  if (models.length > 0) {
    parts.push(
      SECTION_SEPARATOR +
        '// Model interfaces\n// =============================================================================\n',
      models.map(renderModelInterface).join('\n\n'),
    )

    parts.push(
      SECTION_SEPARATOR + '// Input types\n// =============================================================================\n',
      models
        .flatMap((m) => [
          renderWhereInput(m),
          renderWhereUniqueInput(m),
          renderCreateInput(m),
          renderUpdateInput(m),
        ])
        .join('\n\n'),
    )

    parts.push(
      SECTION_SEPARATOR +
        '// REST client\n// =============================================================================\n',
      renderRestClientClass(models),
    )
  }

  return parts.join('\n') + '\n'
}

/** Runs the generator: writes `rest-client.ts` to the resolved output directory. */
export async function onGenerate(options: GeneratorOptions): Promise<void> {
  const outputDir = resolveOutput(options)
  fs.mkdirSync(outputDir, { recursive: true })
  const content = generateContent(options.dmmf)
  fs.writeFileSync(path.join(outputDir, 'rest-client.ts'), content, 'utf-8')
}

