import type { DatamodelEnum, Field, Model } from '@prisma/dmmf'

/** Maps Prisma scalar type names to their TypeScript equivalents. */
const SCALAR_TYPE_MAP: Readonly<Record<string, string>> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Boolean: 'boolean',
  DateTime: 'Date',
  Json: 'unknown',
  Bytes: 'Uint8Array',
  BigInt: 'bigint',
  Decimal: 'number',
}

/** Maps a DMMF field to its TypeScript type representation. */
export function dmmfFieldToTsType(field: Field): string {
  let baseType: string
  switch (field.kind) {
    case 'scalar':
      baseType = SCALAR_TYPE_MAP[field.type] ?? 'unknown'
      break
    case 'enum':
    case 'object':
      baseType = field.type
      break
    default:
      baseType = 'unknown'
  }
  if (field.isList) {
    return `${baseType}[]`
  }
  if (!field.isRequired) {
    return `${baseType} | null`
  }
  return baseType
}

/** Renders a Prisma enum definition as a TypeScript union type. */
export function renderEnum(enumDef: DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  const doc = enumDef.documentation ? `/** ${enumDef.documentation} */\n` : ''
  return `${doc}export type ${enumDef.name} = ${values}`
}

/** Renders a Prisma model definition as a TypeScript interface. */
export function renderModelInterface(model: Model): string {
  const doc = model.documentation ? `/** ${model.documentation} */\n` : ''
  const fields = model.fields
    .filter((f) => f.kind !== 'unsupported')
    .map((f) => {
      const fieldDoc = f.documentation ? `  /** ${f.documentation} */\n` : ''
      // Singular relation fields are optional since they may not be eagerly loaded
      const optional = f.kind === 'object' && !f.isList ? '?' : ''
      return `${fieldDoc}  ${f.name}${optional}: ${dmmfFieldToTsType(f)}`
    })
    .join('\n')
  return `${doc}export interface ${model.name} {\n${fields}\n}`
}

/** Renders a filter input type for querying model records. */
export function renderWhereInput(model: Model): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .map((f) => `  ${f.name}?: ${dmmfFieldToTsType(f)}`)
    .join('\n')
  return `export interface ${model.name}WhereInput {\n${fields}\n}`
}

/** Renders a unique-filter input type for addressing individual model records. */
export function renderWhereUniqueInput(model: Model): string {
  const uniqueFields = model.fields.filter(
    (f) => (f.kind === 'scalar' || f.kind === 'enum') && (f.isId || f.isUnique),
  )
  const fields = uniqueFields.map((f) => `  ${f.name}?: ${dmmfFieldToTsType(f)}`).join('\n')
  return `export interface ${model.name}WhereUniqueInput {\n${fields || '  [key: string]: unknown'}\n}`
}

/** Renders an input type for creating a new model record. */
export function renderCreateInput(model: Model): string {
  const fields = model.fields
    .filter((f) => (f.kind === 'scalar' || f.kind === 'enum') && !f.isReadOnly)
    .map((f) => {
      // Auto-generated or default-valued fields are optional on create
      const optional = !f.isRequired || f.hasDefaultValue || f.isId ? '?' : ''
      return `  ${f.name}${optional}: ${dmmfFieldToTsType(f)}`
    })
    .join('\n')
  return `export interface ${model.name}CreateInput {\n${fields}\n}`
}

/** Renders an input type for updating fields of an existing model record. */
export function renderUpdateInput(model: Model): string {
  const fields = model.fields
    .filter((f) => (f.kind === 'scalar' || f.kind === 'enum') && !f.isReadOnly && !f.isId)
    .map((f) => `  ${f.name}?: ${dmmfFieldToTsType(f)}`)
    .join('\n')
  return `export interface ${model.name}UpdateInput {\n${fields}\n}`
}

/**
 * Converts a PascalCase model name to a kebab-case URL path with a plural suffix.
 *
 * Examples: `User` → `/users`, `BlogPost` → `/blog-posts`
 */
export function modelNameToPath(name: string): string {
  const kebab = name.split(/(?=[A-Z])/).filter(Boolean).join('-').toLowerCase()
  return `/${kebab}s`
}

/** Converts a PascalCase model name to a camelCase property accessor name. */
export function modelNameToCamelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

/** Renders the typed CRUD accessor object for one model as a `RestClient` class property. */
export function renderModelAccessor(model: Model): string {
  const propName = modelNameToCamelCase(model.name)
  const path = modelNameToPath(model.name)
  const idField = model.fields.find((f) => f.isId)
  // Fall back to first value of the where object for models without a single @id
  const idExpr = idField ? `where.${idField.name}` : 'Object.values(where)[0]'
  const n = model.name

  return `  /** CRUD operations for the \`${n}\` model. */
  readonly ${propName} = {
    /** Returns a list of \`${n}\` records matching the given filter. */
    findMany: (params?: {
      where?: ${n}WhereInput
      skip?: number
      take?: number
      orderBy?: Partial<Record<keyof ${n}, 'asc' | 'desc'>>
    }): Promise<${n}[]> =>
      this.#request<${n}[]>('GET', '${path}', undefined, params as Record<string, unknown>),

    /** Returns the \`${n}\` record matching the unique filter, or \`null\` if not found. */
    findUnique: (where: ${n}WhereUniqueInput): Promise<${n} | null> =>
      this.#request<${n} | null>('GET', \`${path}/\${${idExpr}}\`),

    /** Creates and returns a new \`${n}\` record. */
    create: (data: ${n}CreateInput): Promise<${n}> =>
      this.#request<${n}>('POST', '${path}', data),

    /** Updates and returns an existing \`${n}\` record. */
    update: (where: ${n}WhereUniqueInput, data: ${n}UpdateInput): Promise<${n}> =>
      this.#request<${n}>('PUT', \`${path}/\${${idExpr}}\`, data),

    /** Deletes and returns the matching \`${n}\` record. */
    delete: (where: ${n}WhereUniqueInput): Promise<${n}> =>
      this.#request<${n}>('DELETE', \`${path}/\${${idExpr}}\`),
  }`
}

/** Renders the full `RestClient` class with all model accessor properties. */
export function renderRestClientClass(models: readonly Model[]): string {
  const accessors = models.map(renderModelAccessor).join('\n\n')

  return `export class RestClient {
  readonly #baseUrl: string
  readonly #headers: Record<string, string>

  constructor(options: { baseUrl: string; headers?: Record<string, string> }) {
    this.#baseUrl = options.baseUrl.replace(/\\/$/, '')
    this.#headers = options.headers ?? {}
  }

  async #request<T>(
    method: string,
    path: string,
    body?: unknown,
    params?: Record<string, unknown>,
  ): Promise<T> {
    const url = new URL(\`\${this.#baseUrl}\${path}\`)
    if (params !== undefined) {
      for (const [key, value] of Object.entries(params)) {
        if (value !== undefined) {
          url.searchParams.set(key, JSON.stringify(value))
        }
      }
    }
    const response = await fetch(url.toString(), {
      method,
      headers: { 'Content-Type': 'application/json', ...this.#headers },
      body: body !== undefined ? JSON.stringify(body) : undefined,
    })
    if (!response.ok) {
      throw new Error(\`HTTP \${response.status}: \${response.statusText}\`)
    }
    return response.json() as Promise<T>
  }

${accessors}
}`
}

